1	export type Cell = [number, number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const neighborsOf = ([x, y]: Cell): Cell[] => {
6	  const neighbors: Cell[] = [];
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      neighbors.push([x + dx, y + dy]);
11	    }
12	  }
13	  return neighbors;
14	};
15	
16	const shouldLive = (liveNeighborCount: number, isCurrentlyAlive: boolean): boolean =>
17	  liveNeighborCount === 3 || (liveNeighborCount === 2 && isCurrentlyAlive);
18	
19	export function nextGeneration(livingCells: Cell[]): Cell[] {
20	  const liveKeys = new Set(livingCells.map(cellKey));
21	  const candidates = new Map<string, { cell: Cell; liveNeighborCount: number }>();
22	
23	  for (const cell of livingCells) {
24	    for (const neighbor of neighborsOf(cell)) {
25	      const k = cellKey(neighbor);
26	      const existing = candidates.get(k);
27	      if (existing) existing.liveNeighborCount++;
28	      else candidates.set(k, { cell: neighbor, liveNeighborCount: 1 });
29	    }
30	  }
31	
32	  const result: Cell[] = [];
33	  for (const [k, { cell, liveNeighborCount }] of candidates) {
34	    if (shouldLive(liveNeighborCount, liveKeys.has(k))) result.push(cell);
35	  }
36	  return result;
37	}
